// Created: 2026-05-18

/**
 * Tests for per-event payload schemas (M141-2 step 3, #1864).
 *
 * The spec defines payload field shapes for 13 of the 19 events;
 * the remaining 6 (SessionEnd, Setup, InstructionsLoaded, WorktreeCreate,
 * WorktreeRemove, ConfigChange) intentionally stay envelope-only because
 * their payload shapes are undocumented at the CC layer we observe.
 *
 * This test enforces:
 *   1. Events with payload blocks emit the expected properties + required fields
 *   2. Events without payload blocks still emit an open schema (backwards compat)
 *   3. Required fields are a subset of the properties set
 */

import { describe, it, expect } from 'vitest';
import {
  HOOK_EVENT_NAMES,
  HOOK_EVENT_SCHEMAS,
  type HookEventName,
} from '../src/index.js';

const EVENTS_WITH_PAYLOAD: ReadonlyArray<HookEventName> = [
  'SessionStart',
  'UserPromptSubmit',
  'PreToolUse',
  'PostToolUse',
  'PostToolUseFailure',
  'PermissionRequest',
  'SubagentStart',
  'SubagentStop',
  'Stop',
  'Notification',
  'PreCompact',
  'TeammateIdle',
  'TaskCompleted',
];

const EVENTS_WITHOUT_PAYLOAD: ReadonlyArray<HookEventName> = [
  'SessionEnd',
  'Setup',
  'InstructionsLoaded',
  'WorktreeCreate',
  'WorktreeRemove',
  'ConfigChange',
];

describe('per-event payload schemas (#1864)', () => {
  it('covers all 19 events', () => {
    expect(EVENTS_WITH_PAYLOAD.length + EVENTS_WITHOUT_PAYLOAD.length).toBe(
      HOOK_EVENT_NAMES.length,
    );
  });

  describe('events with payload schemas', () => {
    for (const name of EVENTS_WITH_PAYLOAD) {
      it(`${name}: payload schema has properties block`, () => {
        const schema = HOOK_EVENT_SCHEMAS[name];
        const payload = schema.properties?.payload;
        expect(payload, `${name}.payload is missing`).toBeDefined();
        expect(payload?.type).toBe('object');
        expect(payload?.properties).toBeTypeOf('object');
      });
    }
  });

  describe('events without payload schemas', () => {
    for (const name of EVENTS_WITHOUT_PAYLOAD) {
      it(`${name}: payload schema is open (envelope-only)`, () => {
        const payload = HOOK_EVENT_SCHEMAS[name].properties?.payload;
        expect(payload).toBeDefined();
        // No properties block = envelope-only; additionalProperties stays open
        expect(payload?.additionalProperties).toBe(true);
        expect(payload?.required).toBeUndefined();
      });
    }
  });

  describe('payload schema field-level structure', () => {
    it('PreToolUse requires tool_name + tool_input', () => {
      const payload = HOOK_EVENT_SCHEMAS.PreToolUse.properties?.payload;
      expect(payload?.required).toEqual(['tool_name', 'tool_input']);
      const props = payload?.properties ?? {};
      expect(Object.keys(props).sort()).toEqual(
        ['tool_input', 'tool_name', 'tool_use_id'].sort(),
      );
      expect(props['tool_name']?.type).toBe('string');
      expect(props['tool_input']?.type).toBe('object');
    });

    it('Notification requires message', () => {
      const payload = HOOK_EVENT_SCHEMAS.Notification.properties?.payload;
      expect(payload?.required).toEqual(['message']);
    });

    it('Stop has no required fields (all optional)', () => {
      const payload = HOOK_EVENT_SCHEMAS.Stop.properties?.payload;
      expect(payload?.required).toBeUndefined();
      expect(payload?.properties).toMatchObject({
        last_assistant_message: { type: 'string' },
        stop_hook_active: { type: 'boolean' },
      });
    });

    it('TaskCompleted has number-typed fields', () => {
      const payload = HOOK_EVENT_SCHEMAS.TaskCompleted.properties?.payload;
      expect(payload?.properties?.['token_count']?.type).toBe('number');
      expect(payload?.properties?.['tool_uses']?.type).toBe('number');
    });
  });

  describe('required fields are a subset of properties', () => {
    for (const name of HOOK_EVENT_NAMES) {
      it(`${name}: required ⊆ properties`, () => {
        const payload = HOOK_EVENT_SCHEMAS[name].properties?.payload;
        const required = payload?.required ?? [];
        const props = payload?.properties ?? {};
        for (const r of required) {
          expect(
            Object.prototype.hasOwnProperty.call(props, r),
            `${name}.payload.required[${r}] missing from properties`,
          ).toBe(true);
        }
      });
    }
  });
});
